            em_vals = []
            for j in range(8):
                ex = row.get(f'states.{j}.ex_max', '')
                em = row.get(f'states.{j}.em_max', '')
                if ex:
                    try: ex_vals.append(float(ex))
                    except: pass
                if em:
                    try: em_vals.append(float(em))
                    except: pass

            print(f'{name}: PDB={pdb}, ex={ex_vals}, em={em_vals}')
